import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.time.Duration;
import java.util.Optional;

@Service
public class CategoryCacheService {
    private static final String PREFIX = "category:";
    private static final Duration TTL = Duration.ofHours(1);

    private final RedisTemplate<String, Object> redis;
    private final CategoryRepository repo;

    CategoryCacheService(RedisTemplate<String,Object> r, CategoryRepository cr) {
        redis=r; repo=cr;
    }

    @SuppressWarnings("unchecked")
    public Optional<Category> findById(Long id) {
        String key = PREFIX + id;             // 'category:5'
        Object cached = redis.opsForValue().get(key);
        if (cached != null) {
            return Optional.of((Category) cached);  // cache HIT
        }
        // Cache MISS:
        Optional<Category> result = repo.findById(id);
        result.ifPresent(c -> redis.opsForValue().set(key, c, TTL));
        return result;
    }

    @Transactional
    public void delete(Long id) {
        repo.deleteById(id);
        redis.delete(PREFIX + id);            // evict from Redis too
    }

    @Transactional
    public Category update(Category category) {
        Category saved = repo.save(category);
        redis.opsForValue().set(PREFIX + saved.getId(), saved, TTL);  // refresh cache
        return saved;
    }

    interface CategoryRepository extends org.springframework.data.jpa.repository.JpaRepository<Category,Long>{}
    record Category(Long id, String name, String parentId){}
}

