@Service
public class UserProfileHashService {
    private final RedisTemplate<String, String> redis;  // String template for Hash fields

    UserProfileHashService(RedisTemplate<String,String> r) { redis=r; }

    private String key(String uid) { return "user:profile:" + uid; }

    // HSET user:profile:U001 name 'Aisha' email 'a@test.com' city 'Mumbai' plan 'Pro'
    // EXPIRE user:profile:U001 7200
    public void cacheProfile(UserProfile profile) {
        String k = key(profile.userId());
        redis.opsForHash().putAll(k, Map.of(
            "name",  profile.name(),
            "email", profile.email(),
            "city",  profile.city(),
            "plan",  profile.plan()
        ));
        redis.expire(k, Duration.ofHours(2));
    }

    // HGETALL user:profile:U001 → Map of all fields
    public Optional<UserProfile> getProfile(String userId) {
        Map<Object, Object> fields = redis.opsForHash().entries(key(userId));
        if (fields.isEmpty()) return Optional.empty();
        return Optional.of(new UserProfile(
            userId,
            (String) fields.get("name"),
            (String) fields.get("email"),
            (String) fields.get("city"),
            (String) fields.get("plan")
        ));
    }

    // HSET user:profile:U001 city 'Delhi'  ← updates ONLY city field!
    public void updateCity(String userId, String newCity) {
        redis.opsForHash().put(key(userId), "city", newCity);
    }

    // HGET user:profile:U001 plan  ← reads ONLY plan field
    public String getPlan(String userId) {
        return (String) redis.opsForHash().get(key(userId), "plan");
    }

    record UserProfile(String userId, String name, String email, String city, String plan) {}
}

