import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.data.redis.core.ZSetOperations;
import org.springframework.stereotype.Service;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class TradingLeaderboard {
    private static final String KEY = "leaderboard:daily-pnl";
    private final RedisTemplate<String, String> redis;

    TradingLeaderboard(RedisTemplate<String,String> r) { redis=r; }

    // ZINCRBY leaderboard:daily-pnl +amount traderId
    public void recordPnL(String traderId, double amount) {
        redis.opsForZSet().incrementScore(KEY, traderId, amount);
    }

    // ZREVRANK: 0 = highest scorer = rank 1
    public Long getRank(String traderId) {
        return redis.opsForZSet().reverseRank(KEY, traderId);
        // Returns null if traderId not in the board
    }

    // ZREVRANGE leaderboard:daily-pnl 0 (n-1) → top n trader IDs
    public List<String> getTopN(int n) {
        Set<String> result = redis.opsForZSet().reverseRange(KEY, 0, n - 1);
        return result != null ? new ArrayList<>(result) : List.of();
    }

    // ZREVRANGEBYSCORE with scores:
    public List<Map<String, Object>> getTopNWithScores(int n) {
        Set<ZSetOperations.TypedTuple<String>> result =
            redis.opsForZSet().reverseRangeWithScores(KEY, 0, n - 1);
        if (result == null) return List.of();

        return result.stream()
            .map(t -> Map.<String, Object>of(
                "traderId", t.getValue(),
                "pnl",      t.getScore()
            ))
            .collect(Collectors.toList());
    }

    // DEL leaderboard:daily-pnl
    public void resetDailyBoard() {
        redis.delete(KEY);
    }

    // Count traders on board:
    public long getBoardSize() {
        Long size = redis.opsForZSet().size(KEY);
        return size != null ? size : 0L;
    }
}

