import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.Optional;

@Service
public class InstrumentCacheService {
    private static final String PREFIX    = "instrument:";
    private static final String NONE      = "__NONE__";          // null sentinel
    private static final Duration REAL_TTL = Duration.ofHours(6);
    private static final Duration NULL_TTL = Duration.ofMinutes(5); // SHORT!

    private final RedisTemplate<String, Object> redis;
    private final InstrumentRepository repo;

    InstrumentCacheService(RedisTemplate<String,Object> r, InstrumentRepository ir) {
        redis=r; repo=ir;
    }

    public Optional<Instrument> findBySymbol(String symbol) {
        String key = PREFIX + symbol.toUpperCase();  // 'instrument:TCS'
        Object cached = redis.opsForValue().get(key);

        // Null sentinel: we know this symbol doesn't exist
        if (NONE.equals(cached)) {
            return Optional.empty();  // no DB query!
        }

        // Real object: return directly
        if (cached instanceof Instrument i) {
            return Optional.of(i);   // cache HIT
        }

        // Cache MISS: query DB
        Optional<Instrument> result = repo.findBySymbol(symbol);
        if (result.isPresent()) {
            // Cache real data with LONG TTL:
            redis.opsForValue().set(key, result.get(), REAL_TTL);
        } else {
            // Cache 'not found' with SHORT TTL (entity may be created soon):
            redis.opsForValue().set(key, NONE, NULL_TTL);
        }
        return result;
    }

    interface InstrumentRepository { Optional<Instrument> findBySymbol(String s); }
    record Instrument(String symbol, String fullName, String sector) {}
}

