import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.Optional;

@Service
public class StampedeSafeProductService {
    private final RedisTemplate<String, Object> redis;
    private final ProductRepository repo;

    StampedeSafeProductService(RedisTemplate<String,Object> r, ProductRepository pr) {
        redis=r; repo=pr;
    }

    @SuppressWarnings("unchecked")
    public Optional<Product> findById(String id) {
        String key  = "product:" + id;
        String lock = key + ":lock";

        // Fast path:
        Object cached = redis.opsForValue().get(key);
        if (cached instanceof Product p) return Optional.of(p);

        // Slow path — try to acquire lock:
        Boolean acquired = redis.opsForValue()
            .setIfAbsent(lock, "1", Duration.ofSeconds(10));

        if (Boolean.TRUE.equals(acquired)) {
            try {
                // DOUBLE-CHECK: another thread may have built cache while we waited for lock
                // Without this: two sequential threads both query DB unnecessarily
                Object refetched = redis.opsForValue().get(key);
                if (refetched instanceof Product p) return Optional.of(p);

                // We own the rebuild:
                Optional<Product> result = repo.findById(id);
                result.ifPresent(product ->
                    redis.opsForValue().set(key, product, Duration.ofMinutes(10)));
                return result;
            } finally {
                redis.delete(lock);  // ALWAYS release lock, even on exception
            }
        } else {
            // Another thread is rebuilding — wait briefly:
            try { Thread.sleep(50); } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
            Object afterWait = redis.opsForValue().get(key);
            if (afterWait instanceof Product p) return Optional.of(p);

            // Still not there (lock holder may be slow) — fallback to DB:
            return repo.findById(id);
        }
    }

    interface ProductRepository { Optional<Product> findById(String id); }
    record Product(String id, String name, double price) {}

    // WHY DOUBLE-CHECK?
    // Thread A: cache miss at T=0, tries to acquire lock
    // Thread B: acquired lock at T=-1, queried DB, is storing in cache, will release lock
    // Thread A: acquires lock after Thread B releases
    // Without double-check: Thread A queries DB again (unnecessary!)
    // With double-check: Thread A sees Thread B's cached result → returns from cache!
}

