import com.github.benmanes.caffeine.cache.Cache;
import com.github.benmanes.caffeine.cache.Caffeine;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import jakarta.annotation.PostConstruct;
import java.time.Duration;
import java.util.Optional;

@Service
public class MultiLevelCacheService {
    // L1: Caffeine in-JVM cache (nanoseconds, limited size)
    private Cache<String, Object> l1Cache;

    // L2: Redis distributed cache (microseconds, larger)
    private final RedisTemplate<String, Object> redis;
    private final ProductRepository repo;

    // Latency guide:
    // L1 (Caffeine): ~0.01ms — JVM heap lookup
    // L2 (Redis):    ~0.3ms  — network + Redis
    // DB:            ~15ms   — network + disk I/O

    MultiLevelCacheService(RedisTemplate<String,Object> r, ProductRepository pr) {
        redis=r; repo=pr;
    }

    @PostConstruct
    void initL1() {
        l1Cache = Caffeine.newBuilder()
            .maximumSize(200)                    // max 200 items in JVM heap
            .expireAfterWrite(Duration.ofSeconds(30))  // short TTL: consistency
            .build();
    }

    @SuppressWarnings("unchecked")
    public Optional<Product> findById(String id) {
        String key = "product:" + id;

        // L1 check (0.01ms):
        Object l1 = l1Cache.getIfPresent(key);
        if (l1 instanceof Product p) {
            System.out.println("L1 HIT: " + id);
            return Optional.of(p);
        }

        // L2 check (0.3ms):
        Object l2 = redis.opsForValue().get(key);
        if (l2 instanceof Product p) {
            System.out.println("L2 HIT: " + id);
            l1Cache.put(key, p);  // backfill L1
            return Optional.of(p);
        }

        // DB (15ms):
        System.out.println("DB HIT: " + id);
        Optional<Product> result = repo.findById(id);
        result.ifPresent(p -> {
            redis.opsForValue().set(key, p, Duration.ofMinutes(10));  // fill L2
            l1Cache.put(key, p);                                       // fill L1
        });
        return result;
    }

    public Product update(Product product) {
        Product saved = repo.save(product);
        String key = "product:" + saved.getId();
        redis.opsForValue().set(key, saved, Duration.ofMinutes(10));  // update L2
        l1Cache.invalidate(key);     // invalidate L1 (each instance must do this!)
        // NOTE: In multi-instance deployment, other instances' L1 caches still have stale data!
        // Solution: use Redis Pub/Sub to broadcast L1 invalidation (Topic 18.5)
        return saved;
    }

    interface ProductRepository { Optional<Product> findById(String id); Product save(Product p); }
    record Product(String id, String name, double price) {}
}

