    private final RedisTemplate<String, String> redis;

    DailyPnLLeaderboard(RedisTemplate<String,String> r) { redis=r; }

    // Record a trade's P&L contribution (atomic increment):
    public void recordTrade(String traderId, double pnl) {
        redis.opsForZSet().incrementScore(KEY, traderId, pnl);
    }

    // Top N with position numbers (1-indexed):
    public List<TraderRank> getTopTradersWithScores(int n) {
        Set<ZSetOperations.TypedTuple<String>> top =
            redis.opsForZSet().reverseRangeWithScores(KEY, 0, n - 1);
        if (top == null) return List.of();

        List<TraderRank> result = new ArrayList<>();
        int position = 1;
        for (ZSetOperations.TypedTuple<String> entry : top) {
            result.add(new TraderRank(
                position++,
                entry.getValue(),
                entry.getScore() != null ? entry.getScore() : 0.0
            ));
        }
        return result;
    }

    // Get trader's rank (1-indexed for display) + their score:
    public Optional<TraderRank> getMyRank(String traderId) {
        Long rank  = redis.opsForZSet().reverseRank(KEY, traderId);
        Double pnl = redis.opsForZSet().score(KEY, traderId);
        if (rank == null || pnl == null) return Optional.empty();
        return Optional.of(new TraderRank((int)(rank + 1), traderId, pnl));
    }

    // End of day: snapshot to DB (stub), then reset:
