        top10.forEach(r -> System.out.printf("  #%d %s: ₹%.2f%n",
            r.position(), r.traderId(), r.pnl()));
        redis.delete(KEY);
        System.out.println("[EOD] Leaderboard reset for tomorrow");
    }

    // Test helper:
    public static void main(String[] args) {
        System.out.println("Leaderboard: record → rank → end-of-day");
    }
}

