import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.*;

@Service
public class BackgroundCacheRefreshService {
    private static final String HOT_KEYS   = "hot:product:keys";  // Hash: key → access count
    private static final Duration THRESHOLD = Duration.ofMinutes(2);  // refresh when TTL < 2 min
    private static final Duration FULL_TTL  = Duration.ofMinutes(10);

    private final RedisTemplate<String, Object> redis;
    private final ProductRepository repo;

    BackgroundCacheRefreshService(RedisTemplate<String,Object> r, ProductRepository pr) {
        redis=r; repo=pr;
    }

    // Called on every cache access — tracks hot keys:
    public void recordAccess(String productId) {
        // HINCR hot:product:keys product:P001  ← increment access counter
        redis.opsForHash().increment(HOT_KEYS, "product:" + productId, 1);
    }

    // Every 8 minutes: proactively refresh hot keys before they expire:
    @Scheduled(fixedRate = 480_000)  // 8 minutes = 480,000ms
    public void refreshHotKeys() {
        Map<Object, Object> hotKeys = redis.opsForHash().entries(HOT_KEYS);
        int refreshed = 0;

        for (Map.Entry<Object, Object> entry : hotKeys.entrySet()) {
            String key   = (String) entry.getKey();    // 'product:P001'
            long   count = ((Number) entry.getValue()).longValue();

            if (count < 10) continue;  // not hot enough to proactively refresh

            // Check remaining TTL:
            Long ttl = redis.getExpire(key);  // seconds remaining
            if (ttl == null || ttl > THRESHOLD.getSeconds()) continue;  // TTL still healthy

            // TTL below threshold — refresh from DB:
            String productId = key.replace("product:", "");
            repo.findById(productId).ifPresent(product -> {
                redis.opsForValue().set(key, product, FULL_TTL);  // reset TTL
                refreshed++;
            });
        }

        if (refreshed > 0)
            System.out.printf("[CacheRefresh] Proactively refreshed %d hot keys%n", refreshed);

        // Reset access counters for next cycle:
        redis.delete(HOT_KEYS);
    }

    interface ProductRepository { Optional<Object> findById(String id); }
}

