import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.time.LocalDate;
import java.util.*;

@Service
public class DealCacheService {
    private static final String NONE     = "__NONE__";
    private static final Duration TTL    = Duration.ofMinutes(5);
    private static final Duration NULLTL = Duration.ofMinutes(1);
    private static final Duration LOCKTL = Duration.ofSeconds(10);

    private final RedisTemplate<String,Object> redis;
    private final DealRepository repo;

    DealCacheService(RedisTemplate<String,Object> r, DealRepository dr){redis=r;repo=dr;}

    private String cacheKey(String city,LocalDate date){return "deals:"+city+":"+date;}
    private String lockKey(String city,LocalDate date){return cacheKey(city,date)+":lock";}

    @SuppressWarnings("unchecked")
    public List<Object> getTopDeals(String city, LocalDate date){
        String key=cacheKey(city,date);

        // Fast path:
        Object cached=redis.opsForValue().get(key);
        if(NONE.equals(cached)) return List.of();           // cached empty
        if(cached instanceof List<?> l) return (List<Object>)l;  // cache hit

        // Acquire mutex:
        Boolean locked=redis.opsForValue().setIfAbsent(lockKey(city,date),"1",LOCKTL);
        if(Boolean.TRUE.equals(locked)){
            try{
                // Double-check:
                Object check=redis.opsForValue().get(key);
                if(check instanceof List<?> l) return (List<Object>)l;

                List<Object> deals=repo.findByCity(city,date);
                if(deals.isEmpty()){
                    redis.opsForValue().set(key,NONE,NULLTL);
                }else{
                    redis.opsForValue().set(key,deals,TTL);
                }
                return deals;
            }finally{
                redis.delete(lockKey(city,date));
            }
        }else{
            try{Thread.sleep(50);}catch(InterruptedException e){Thread.currentThread().interrupt();}
            Object r=redis.opsForValue().get(key);
            if(r instanceof List<?> l) return (List<Object>)l;
            return repo.findByCity(city,date); // fallback
        }
    }

    public void refreshDeals(String city, LocalDate date){
        redis.delete(cacheKey(city,date));  // evict current entry
        getTopDeals(city,date);             // rebuild immediately
    }

    interface DealRepository { List<Object> findByCity(String city, LocalDate date); }

    static void test(){
        System.out.println("DealCacheService: stampede + null-object protection");
    }
    public static void main(String[] a){test();}
}

