import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.util.List;

@Service
public class UserActivityFeedService {
    private static final int MAX_SIZE = 20;
    private final RedisTemplate<String, String> redis;

    UserActivityFeedService(RedisTemplate<String,String> r) { redis=r; }

    private String key(String userId) { return "activity:feed:" + userId; }

    // LPUSH: add to front (most recent first)
    // LTRIM: keep only first MAX_SIZE elements
    // Combined: O(1) fixed-size queue!
    public void pushActivity(String userId, String activity) {
        String k = key(userId);
        redis.opsForList().leftPush(k, activity);       // LPUSH
        redis.opsForList().trim(k, 0, MAX_SIZE - 1);   // LTRIM: keep 0..19 = 20 entries
        // No TTL needed for activity feed — or set to 7 days:
        // redis.expire(k, Duration.ofDays(7));
    }

    // LRANGE: get n most recent (already at front due to LPUSH):
    public List<String> getRecentActivities(String userId, int n) {
        return redis.opsForList().range(key(userId), 0, n - 1);
        // LRANGE key 0 (n-1): returns first n elements (most recent)
    }

    public void clearFeed(String userId) {
        redis.delete(key(userId));
    }

    public long getFeedSize(String userId) {
        Long size = redis.opsForList().size(key(userId));
        return size != null ? size : 0L;
    }

    // Why LPUSH + LTRIM?
    // LPUSH: pushes to head of list (O(1))
    // LTRIM: removes from tail (O(1) for trim operation)
    // Together: O(1) append to bounded list
    // Alternative: append to tail and trim from head (RPUSH + LTRIM from right)
    // Use LPUSH when you want newest-first ordering

    public static void main(String[] args) {
        System.out.println("Activity feed: LPUSH + LTRIM = O(1) bounded queue");
        System.out.println("After pushing 21 items: only last " + MAX_SIZE + " kept");
    }
}

