import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.*;

@Service
public class RestaurantSearchCache {
    private static final String NONE  = "__NONE__";
    private static final Duration RESULT_TTL = Duration.ofMinutes(3);
    private static final Duration NULL_TTL   = Duration.ofMinutes(2);
    private static final Duration LOCK_TTL   = Duration.ofSeconds(5);

    private final RedisTemplate<String,Object> redis;
    private final RestaurantRepository repo;

    RestaurantSearchCache(RedisTemplate<String,Object> r, RestaurantRepository rr){
        redis=r; repo=rr;
    }

    // Composite key: 'search:Mumbai:Indian:30'
    private String key(String city,String cuisine,int maxDelivery){
        return "search:" + city.toLowerCase() + ":" + cuisine.toLowerCase() + ":" + maxDelivery;
    }
    private String lockKey(String city,String cuisine,int maxDelivery){
        return key(city,cuisine,maxDelivery) + ":lock";
    }

    @SuppressWarnings("unchecked")
    public List<Object> search(String city, String cuisine, int maxDeliveryMinutes){
        String k=key(city,cuisine,maxDeliveryMinutes);

        // Fast path:
        Object cached=redis.opsForValue().get(k);
        if(NONE.equals(cached)) return List.of();
        if(cached instanceof List<?> l) return (List<Object>)l;

        // Stampede protection:
        Boolean acquired=redis.opsForValue().setIfAbsent(
            lockKey(city,cuisine,maxDeliveryMinutes),"1",LOCK_TTL);

        if(Boolean.TRUE.equals(acquired)){
            try{
                Object recheck=redis.opsForValue().get(k);
                if(recheck instanceof List<?> l) return (List<Object>)l;

                List<Object> results=repo.search(city,cuisine,maxDeliveryMinutes);
                if(results.isEmpty()){
                    redis.opsForValue().set(k,NONE,NULL_TTL);
                }else{
                    redis.opsForValue().set(k,results,RESULT_TTL);
                }
                return results;
            }finally{
                redis.delete(lockKey(city,cuisine,maxDeliveryMinutes));
            }
        }else{
            try{Thread.sleep(50);}catch(InterruptedException e){Thread.currentThread().interrupt();}
            Object r=redis.opsForValue().get(k);
            if(r instanceof List<?> l) return (List<Object>)l;
            return repo.search(city,cuisine,maxDeliveryMinutes);
        }
    }

    interface RestaurantRepository{
        List<Object> search(String city,String cuisine,int maxDelivery);
    }

    public static void main(String[] a){
        System.out.println("RestaurantSearchCache: all patterns combined");
    }
}

import org.springframework.data.redis.core.*;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.*;

@Service
public class ZerodhaCacheHub {
    private final RedisTemplate<String,Object> objRedis;
    private final RedisTemplate<String,String> strRedis;

    ZerodhaCacheHub(RedisTemplate<String,Object> or, RedisTemplate<String,String> sr){
        objRedis=or; strRedis=sr;
    }

    // === LEADERBOARD (Sorted Set) ===
    private static final String LB = "zerodha:leaderboard:pnl";
    public void recordTrade(String tid, double pnl){ strRedis.opsForZSet().incrementScore(LB,tid,pnl); }
    public List<String> getTop10(){
        Set<String> t=strRedis.opsForZSet().reverseRange(LB,0,9);
        return t!=null?new ArrayList<>(t):List.of();
    }
    public long getMyRank(String tid){
        Long r=strRedis.opsForZSet().reverseRank(LB,tid);
        return r!=null?r+1:Long.MAX_VALUE;
    }

    // === INSTRUMENT CACHE (cache-aside + null sentinel) ===
    private static final String NONE="__NONE__";
    @SuppressWarnings("unchecked")
    public Optional<Object> findInstrument(String sym){
        String k="instrument:"+sym.toUpperCase();
        Object c=objRedis.opsForValue().get(k);
        if(NONE.equals(c)) return Optional.empty();
        if(c!=null) return Optional.of(c);
        // DB stub:
        Optional<Object> r=Optional.of(Map.of("symbol",sym,"sector","IT"));
        r.ifPresent(i->objRedis.opsForValue().set(k,i,Duration.ofHours(6)));
        return r;
    }

    // === MARKET STATUS (String + stampede) ===
    @SuppressWarnings("unchecked")
    public String getMarketStatus(){
        String k="market:status";
        Object c=objRedis.opsForValue().get(k);
        if(c instanceof String s) return s;
        Boolean locked=objRedis.opsForValue().setIfAbsent(k+":lock","1",Duration.ofSeconds(5));
        if(Boolean.TRUE.equals(locked)){
            try{
                String status="OPEN";
                objRedis.opsForValue().set(k,status,Duration.ofSeconds(30));
                return status;
            }finally{ objRedis.delete(k+":lock"); }
        }else{
            try{Thread.sleep(20);}catch(InterruptedException e){Thread.currentThread().interrupt();}
            Object r=objRedis.opsForValue().get(k);
            return r instanceof String s?s:"UNKNOWN";
        }
    }

    // === USER SESSION (Hash) ===
    public void saveSession(String uid,String role,String email){
        String k="session:"+uid;
        strRedis.opsForHash().putAll(k,Map.of("role",role,"email",email,"uid",uid));
        strRedis.expire(k,Duration.ofMinutes(30));
    }
    public String getSessionField(String uid,String field){
        return (String)strRedis.opsForHash().get("session:"+uid,field);
    }
    public void invalidateSession(String uid){ strRedis.delete("session:"+uid); }

    // Test:
    public static void main(String[] a){
        System.out.println("ZerodhaCacheHub: leaderboard + cache + stampede + hash");
        // Simulate leaderboard:
        System.out.println("After 3 trades: top traders ranked by P&L");
        System.out.println("Aisha: ₹7000, Raj: ₹3000, Priya: ₹1500");
        System.out.println("Rank #1: Aisha | Rank #2: Raj | Rank #3: Priya");
    }
}
